import { Hono } from 'hono';
import nodemailer from 'nodemailer';

const app = new Hono();

app.post('/password-reset-request', async (c) => {
  const email = c.req.query('email');
  if (!email) {
    return c.json({ error: 'Email is required' }, 400);
  }

  // Simulate user lookup
  const userExists = await checkUserExists(email);

  if (userExists) {
    // Generate a one-time reset token and send an email
    const resetToken = generateResetToken();
    const resetLink = `https://example.com/reset-password?token=${resetToken}`;

    await sendEmail(email, resetLink);
  }

  // Always return 200 to avoid user enumeration
  return c.json({ message: 'Password reset request processed' }, 200);
});

async function checkUserExists(email: string): Promise<boolean> {
  // Simulate checking if a user exists in the database
  return true; // Replace with actual logic
}

function generateResetToken(): string {
  // Generate a secure one-time token
  return Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
}

async function sendEmail(email: string, resetLink: string): Promise<void> {
  const transporter = nodemailer.createTransport({
    service: 'gmail',
    auth: {
      user: 'your-email@gmail.com', // Replace with your email
      pass: 'your-password' // Replace with your password or use environment variables
    }
  });

  const mailOptions = {
    from: 'your-email@gmail.com', // Replace with your email
    to: email,
    subject: 'Password Reset Request',
    text: `Please click the following link to reset your password: ${resetLink}`
  };

  await transporter.sendMail(mailOptions);
}

export default app;

